var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"……그나저나 주시윤 선배를 찾을 방법은 있어?","JPN":"……ところでアキヤマ先輩を探す方法はあるの？","ENG":"So… You got a plan for how to find Shiyoon?","TWN":"……話說回來，你有想好要怎麼找周時雲前輩嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아카데미 학생들이 도와 주더라도 이 넓은 곳을 전부 뒤지고 다니는 건 무리야.","JPN":"アカデミーの生徒たちが\\n手伝ってくれるとしても、こんな広い場所をすべて探し回るのは無理だよ。","ENG":"Even with all this help, we won't be able to search this entire area.","TWN":"就算學院的學生一起幫忙找，但茫茫人海中是要怎麼找？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……장담은 못하겠지만, 가능성은 있어.","JPN":"……断言はできないけど、可能性はある。","ENG":"I can't guarantee it… but there is a way.","TWN":"雖然我也不太確定這個方法是不是有用……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이 칼, 예전에 주시윤 선배의 피를 흡수한 적이 있거든.","JPN":"この剣、以前アキヤマ先輩の血を吸収したことがあるの。","ENG":"This sword absorbed some of his blood before.","TWN":"這把劍之前有吸收過周時雲前輩的血。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"피를 흡수했다고? 칼이?","JPN":"血を吸収したの？　剣が？","ENG":"Absorbed his blood? This sword?","TWN":"吸血？劍會吸血？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응. 선배의 피에 녹아 있는 클리포트 인자로 칼을 깨우기 위해서라고 했어.","JPN":"うん。先輩の血に溶けているクリフォト・ファクターで剣を起こすためだと言ってた。","ENG":"Yeah. It was to awaken the sword with the Qliphoth Factor in his blood.","TWN":"嗯，因為要利用溶在前輩血裡的卡巴拉因子來喚醒劍。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"직후에 곧바로 방출해 버리긴 했지만……","JPN":"その直後にすぐ放出してしまったけど……","ENG":"Although I had to release it right away…","TWN":"原本是打算喚醒後就要排出的，但是……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래도 한 번 각인된 이상 비슷한 종류의 힘이 어느 방향에 있는지 느낄 수 있어.","JPN":"でも、一度刻印された以上、似たような力がどの方向にあるのか感じられるんだ。","ENG":"But once it's been imprinted, the sword can sense where a similar power might be.","TWN":"不過既然已經刻印過一次，應該可以感應到類似的力量在哪個方向。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"신기한 칼이네……? 그런 게 가능하다고?","JPN":"不思議な剣だね……そんなこともできるの？","ENG":"How fascinating… You can actually do that with a sword?","TWN":"這是什麼神奇的劍……還有這種事？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그 말 듣고 나니까 정말 늑대 같은데?","JPN":"その話を聞くと本当に狼みたいだね。","ENG":"That really makes you sound like a wolf.","TWN":"聽完這些話覺得還真的有點像狼呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"늑대?","JPN":"狼？","ENG":"A wolf?","TWN":"狼？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"응. 한 번 물어뜯은 사냥감은 절대 놓치지 않는 늑대.","JPN":"うん、一度狙った獲物は絶対逃さない狼。","ENG":"Yeah. You know, a wolf that never lets her prey go once she's caught the scent.","TWN":"嗯，一旦咬住獵物就絕對不會鬆口的狼。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"별거 아냐. 아까 그 여자가 널 저주받은 늑대라고 불렀잖아.","JPN":"いや、さっきあの女に呪われた狼と呼ばれたでしょ。","ENG":"Oh, it's nothing really. That lady called you the Cursed Wolf earlier, anyway.","TWN":"沒什麼啦，剛才那女人不是叫你受詛咒的狼嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그런데 그 칼, 네 언니가 가지고 있던 거라고 하지 않았어?","JPN":"ところでその剣、あなたのお姉さんが持っていたものって言ってなかった？","ENG":"By the way, didn't that sword belong to your sister?","TWN":"不過你不是說那把劍原本在你姊姊那嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"처음엔 총 안에 칼이 들어 있는지도 모르더니 잘도 그런 기능이 있다는 걸 알아챘네.","JPN":"最初は銃の中に剣が入っていることすら\\nわからなかったのに、よくそんな機能があることに気づいたね。","ENG":"You didn't even know there was a blade in the gun before. How'd you find out about this imprint thing?","TWN":"一開始連槍裡面有劍都不知道，竟然能發現這把劍有這種用途！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"집에서 매뉴얼이라도 찾은 거야?","JPN":"家でマニュアルでも見つけたの？","ENG":"You find a manual or something?","TWN":"是在家裡找到使用說明書嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};